cards.solution_code:
class AppError(Exception):
    """Root of all app-level errors."""


class ValidationError(AppError):
    """User input failed a check."""


class NotFoundError(AppError):
    """Requested resource isn't there."""

cards.tests:
import pytest
from solution import AppError, NotFoundError, ValidationError

def test_validation_is_an_app_error():
    assert issubclass(ValidationError, AppError)

def test_not_found_is_an_app_error():
    assert issubclass(NotFoundError, AppError)

def test_app_error_catches_either_subclass():
    for exc_cls in (ValidationError, NotFoundError):
        with pytest.raises(AppError):
            raise exc_cls('boom')

def test_message_round_trips_through_str():
    e = ValidationError('email missing')
    assert str(e) == 'email missing'

def test_no_args_construct_works():
    NotFoundError()

